import{_ as a,o as t,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"How Alliance Membership Works","description":"","frontmatter":{},"headers":[],"relativePath":"reference/alliance-membership.md","filePath":"reference/alliance-membership.md"}'),l={name:"reference/alliance-membership.md"};function s(o,e,h,n,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="how-alliance-membership-works" tabindex="-1">How Alliance Membership Works <a class="header-anchor" href="#how-alliance-membership-works" aria-label="Permalink to &quot;How Alliance Membership Works&quot;">​</a></h1><p>A player belongs to one kingdom identity, but their alliance membership can change over time. The tracker keeps that history so imports, event snapshots, and player records still make sense after someone moves, leaves, or gets kicked.</p><h2 id="the-simple-rule" tabindex="-1">The simple rule <a class="header-anchor" href="#the-simple-rule" aria-label="Permalink to &quot;The simple rule&quot;">​</a></h2><ul><li>A player can have only one current alliance at a time.</li><li>A player can have many past alliance memberships in their history.</li></ul><p>If you assign the same player to a different alliance, the old membership is closed and the new one starts.</p><h2 id="membership-sources-you-may-see" tabindex="-1">Membership sources you may see <a class="header-anchor" href="#membership-sources-you-may-see" aria-label="Permalink to &quot;Membership sources you may see&quot;">​</a></h2><p>Each membership record has a source that explains how it happened:</p><table tabindex="0"><thead><tr><th>Source</th><th>What it means in plain language</th></tr></thead><tbody><tr><td><code>manual</code></td><td>A person was added to an alliance by hand.</td></tr><tr><td><code>import</code></td><td>The alliance link came from imported data.</td></tr><tr><td><code>api_sync</code></td><td>The link came from the game API profile data.</td></tr><tr><td><code>kvk</code></td><td>The link was recorded from KvK-related capture or processing.</td></tr><tr><td><code>kicked</code></td><td>The player was removed from the alliance by a kick action.</td></tr><tr><td><code>transfer</code></td><td>The player moved from one alliance to another.</td></tr></tbody></table><h2 id="what-a-kick-does" tabindex="-1">What a kick does <a class="header-anchor" href="#what-a-kick-does" aria-label="Permalink to &quot;What a kick does&quot;">​</a></h2><p>A kick removes the player from the current alliance roster, but it does not erase the player from the kingdom.</p><p>The player&#39;s:</p><ul><li>identity stays</li><li>result history stays</li><li>nickname history stays</li><li>old membership history stays</li></ul><p>That is why <strong>Kick</strong> is safer than delete when someone only left the alliance.</p><h2 id="what-a-transfer-does" tabindex="-1">What a transfer does <a class="header-anchor" href="#what-a-transfer-does" aria-label="Permalink to &quot;What a transfer does&quot;">​</a></h2><p>A transfer changes the player&#39;s current alliance and records that change in membership history. If the player was active inside event participant lists, the old alliance membership is marked as having ended.</p><h2 id="why-this-history-matters" tabindex="-1">Why this history matters <a class="header-anchor" href="#why-this-history-matters" aria-label="Permalink to &quot;Why this history matters&quot;">​</a></h2><p>Membership history helps the tracker explain:</p><ul><li>why old imports matched the player a certain way</li><li>why event participation changed over time</li><li>why a player is no longer on the current alliance roster</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../how-to/kick-player.html">Kick a Player from the Alliance</a></li><li><a href="./../how-to/edit-player.html">Edit Player Details</a></li><li><a href="./../how-to/player-profile.html">Read a Player Profile</a></li><li><a href="./../how-to/delete-restore-player.html">Delete &amp; Restore a Player</a></li></ul>',20)])])}const y=a(l,[["render",s]]);export{p as __pageData,y as default};
